+    fn set_nested_field_rebuilds_parent_chain_without_unwrap_shortcuts() {
+        let mut store = Store::new();
+        let mut state = LuaState::new(&mut store, 0);
+        let parent = LuaTable::new();
+        let child = LuaTable::new();
